import React, { useState, useEffect } from 'react';
import Sidebar from '../Layout/Sidebar';
import MessageList from './MessageList';
import InputArea from './InputArea';
import WelcomeScreen from './WelcomeScreen';
import useChat from '../../hooks/useChat';
import '../../styles/chat-interface.css'; // Use the new CSS file

const ChatContainer = () => {
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false);
  const [theme, setTheme] = useState('light');
  const [isMobile, setIsMobile] = useState(window.innerWidth <= 768);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [chatHistory, setChatHistory] = useState([]);
  const [currentChatId, setCurrentChatId] = useState(null);
  const [showSuggestions, setShowSuggestions] = useState(true);

  const {
    messages,
    inputMessage,
    setInputMessage,
    isLoading,
    isTyping,
    sendMessage,
    clearChat,
    sessionId
  } = useChat();

  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth <= 768);
      if (window.innerWidth > 768) {
        setSidebarOpen(false);
      }
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme);
  }, [theme]);

  useEffect(() => {
    // Update chat history when messages change
    if (messages.length > 1 && sessionId) {
      setChatHistory(prev => {
        const existingChatIndex = prev.findIndex(chat => chat.id === sessionId);
        const firstUserMessage = messages.find(m => m.type === 'user');
        const chatData = {
          id: sessionId,
          messages: messages,
          timestamp: new Date(),
          title: firstUserMessage?.content?.substring(0, 50) || 'New Chat',
          preview: firstUserMessage?.content?.substring(0, 100) || 'No preview'
        };

        if (existingChatIndex >= 0) {
          const updated = [...prev];
          updated[existingChatIndex] = chatData;
          return updated;
        } else {
          return [chatData, ...prev];
        }
      });
      setCurrentChatId(sessionId);
    }
  }, [messages, sessionId]);

  // Hide suggestions after first user message
  useEffect(() => {
    if (messages.length > 1) {
      setShowSuggestions(false);
    }
  }, [messages]);

  const toggleSidebar = () => {
    if (isMobile) {
      setSidebarOpen(!sidebarOpen);
    } else {
      setSidebarCollapsed(!sidebarCollapsed);
    }
  };

  const toggleTheme = () => {
    setTheme(theme === 'light' ? 'dark' : 'light');
  };

  const handleNewChat = () => {
    clearChat();
    setShowSuggestions(true);
    setCurrentChatId(null);
    if (isMobile) {
      setSidebarOpen(false);
    }
  };

  const handleChatSelect = (chatId) => {
    const selectedChat = chatHistory.find(chat => chat.id === chatId);
    if (selectedChat) {
      // Implement chat loading logic here
      setCurrentChatId(chatId);
      setShowSuggestions(false);
    }
    if (isMobile) {
      setSidebarOpen(false);
    }
  };

  const handleDeleteChat = (chatId) => {
    setChatHistory(prev => prev.filter(chat => chat.id !== chatId));
    if (currentChatId === chatId) {
      handleNewChat();
    }
  };

  const handleSuggestionClick = (suggestion) => {
    setInputMessage(suggestion);
    setShowSuggestions(false);
  };

  const handleSendMessage = async () => {
    if (inputMessage.trim()) {
      setShowSuggestions(false);
      await sendMessage();
    }
  };

  return (
    <div className={`chat-interface ${theme}`} data-theme={theme}>
      {/* Mobile Header */}
      {isMobile && (
        <div className="mobile-header">
          <button 
            className="sidebar-toggle"
            onClick={toggleSidebar}
            aria-label="Toggle sidebar"
          >
            <span className="hamburger-icon">
              <span></span>
              <span></span>
              <span></span>
            </span>
          </button>
          
          <div className="header-title">
            <span className="brand-icon">🤖</span>
            <span>StudyBuddy</span>
          </div>
          
          <button 
            className="theme-toggle"
            onClick={toggleTheme}
            aria-label="Toggle theme"
          >
            {theme === 'dark' ? '☀️' : '🌙'}
          </button>
        </div>
      )}

      {/* Enhanced Sidebar with proper props */}
      <div className={`sidebar ${sidebarOpen ? 'open' : ''} ${sidebarCollapsed ? 'collapsed' : ''}`}>
        <div className="sidebar-content">
          {/* Sidebar Header */}
          <div className="sidebar-header">
            <div className="sidebar-title">
              <span className="icon">💬</span>
              {!sidebarCollapsed && <span>Chat History</span>}
            </div>
            {isMobile && (
              <button className="close-sidebar" onClick={() => setSidebarOpen(false)}>
                ✕
              </button>
            )}
          </div>

          {/* New Chat Button */}
          <button className="new-chat-btn" onClick={handleNewChat}>
            <span className="icon">➕</span>
            {!sidebarCollapsed && <span>New Chat</span>}
          </button>

          {/* Search Container */}
          {!sidebarCollapsed && (
            <div className="search-container">
              <input
                type="text"
                placeholder="Search conversations..."
                className="search-input"
              />
              <span className="search-icon">🔍</span>
            </div>
          )}

          {/* Chat History */}
          <div className="chat-history">
            {chatHistory.length === 0 ? (
              !sidebarCollapsed && (
                <div className="no-chats">
                  <div className="no-chats-icon">💭</div>
                  <p>No conversations yet</p>
                  <p className="no-chats-subtitle">Start a new chat to see your history here</p>
                </div>
              )
            ) : (
              <div className="chat-list">
                {chatHistory.map(chat => (
                  <div
                    key={chat.id}
                    className={`chat-item ${chat.id === currentChatId ? 'active' : ''}`}
                    onClick={() => handleChatSelect(chat.id)}
                  >
                    <div className="chat-item-content">
                      <div className="chat-title">{chat.title}</div>
                      {!sidebarCollapsed && (
                        <>
                          <div className="chat-preview">{chat.preview}</div>
                          <div className="chat-time">{chat.timestamp.toLocaleTimeString()}</div>
                        </>
                      )}
                    </div>
                    {!sidebarCollapsed && (
                      <button
                        className="delete-chat"
                        onClick={(e) => {
                          e.stopPropagation();
                          handleDeleteChat(chat.id);
                        }}
                      >
                        🗑️
                      </button>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Sidebar Footer */}
          {!sidebarCollapsed && (
            <div className="sidebar-footer">
              <div className="footer-item">
                <span className="icon">⚡</span>
                <span>Powered by Gemini AI</span>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Sidebar Overlay for mobile */}
      {sidebarOpen && isMobile && (
        <div className="sidebar-overlay" onClick={() => setSidebarOpen(false)} />
      )}

      {/* Main Chat Area */}
      <div className={`main-chat-area ${sidebarOpen ? 'sidebar-open' : ''} ${sidebarCollapsed ? 'sidebar-collapsed' : ''}`}>
        {/* Desktop Header */}
        {!isMobile && (
          <div className="desktop-header">
            <div className="header-left">
              <button 
                className="sidebar-toggle desktop"
                onClick={toggleSidebar}
              >
                <span className="toggle-icon">
                  {sidebarCollapsed ? '☰' : '✕'}
                </span>
              </button>
              <div className="header-title">
                <span className="brand-icon">🤖</span>
                <span>StudyBuddy - AI Academic Companion</span>
              </div>
            </div>
            
            <div className="header-right">
              <button 
                className="theme-toggle desktop"
                onClick={toggleTheme}
              >
                {theme === 'dark' ? '☀️ Light' : '🌙 Dark'}
              </button>
            </div>
          </div>
        )}

        {/* Messages Area */}
        <div className="message-area">
          <div className="messages-container">
            {messages.length <= 1 ? (
              <WelcomeScreen 
                onSuggestionClick={handleSuggestionClick} 
                theme={theme}
              />
            ) : (
              <div className="messages-list">
                <MessageList 
                  messages={messages} 
                  isTyping={isTyping} 
                  theme={theme}
                />
              </div>
            )}
          </div>
        </div>

        {/* Suggestions (shown above input when active) */}
        {showSuggestions && messages.length <= 1 && (
          <div className={`suggestion-chips ${theme}`}>
            <div className="suggestions-header">
              <span className="suggestions-title">✨ Try asking:</span>
            </div>
            <div className="suggestions-grid">
              {[
                { icon: '💻', text: 'Help me with Python code', category: 'Programming' },
                { icon: '📊', text: 'Solve a math problem', category: 'Mathematics' },
                { icon: '🔬', text: 'Explain a science concept', category: 'Science' },
                { icon: '📚', text: 'Analyze literature', category: 'Literature' },
                { icon: '🎯', text: 'Help with homework', category: 'General' },
                { icon: '🌐', text: 'Ask in Hindi/हिंदी', category: 'Language' }
              ].map((suggestion, index) => (
                <button
                  key={index}
                  className="suggestion-chip"
                  onClick={() => handleSuggestionClick(suggestion.text)}
                >
                  <span className="suggestion-icon">{suggestion.icon}</span>
                  <span className="suggestion-text">{suggestion.text}</span>
                  <span className="suggestion-category">{suggestion.category}</span>
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Enhanced Input Area */}
        <div className={`input-area ${theme}`}>
          <div className="input-container">
            <div className="input-wrapper">
              <textarea
                className="message-input"
                placeholder="Ask me anything about programming, math, science, or any subject! 🚀"
                value={inputMessage}
                onChange={(e) => setInputMessage(e.target.value)}
                onKeyPress={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    handleSendMessage();
                  }
                }}
                disabled={isLoading}
                rows="1"
                style={{ resize: 'none' }}
              />
              
              <button
                className={`send-btn ${inputMessage.trim() ? 'active' : ''}`}
                onClick={handleSendMessage}
                disabled={isLoading || !inputMessage.trim()}
                title="Send message"
              >
                {isLoading ? (
                  <div className="loading-spinner">
                    <div className="spinner"></div>
                  </div>
                ) : (
                  <span className="send-icon">🚀</span>
                )}
              </button>
            </div>
          </div>

          {/* Input Footer */}
          <div className="input-footer">
            <span className="input-hint">
              Press Enter to send • Shift+Enter for new line
            </span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ChatContainer;
